svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg = document.getElementById('root');
  var dataLayerEl  = document.getElementById('data-layer');

  var quarters = ["Q1'22","Q2'22","Q3'22","Q4'22","Q1'23","Q2'23","Q3'23","Q4'23"];
  var series = [
    { name:'North America', cls:'1', values:[1.0,  1.5,  2.5,  3.5,  4.75, 5.0,  5.25, 5.25] },
    { name:'Europe',        cls:'2', values:[0.5,  0.5,  1.0,  2.0,  3.0,  3.5,  4.0,  4.25] },
    { name:'Asia-Pacific',  cls:'3', values:[0.25, 0.5,  0.75, 1.25, 2.0,  2.5,  2.75, 3.0 ] }
  ];

  var plotL = 68, plotR = 850, plotT = 100, plotB = 500;
  var n     = quarters.length;
  var step  = (plotR - plotL) / (n - 1);
  var yMin  = 0, yMax = 8;

  function xAt(i) { return plotL + i * step; }
  function yAt(v) { return plotB - (v - yMin) / (yMax - yMin) * (plotB - plotT); }

  function jumpPath(values) {
    var d = 'M' + xAt(0) + ',' + yAt(values[0]);
    for (var i = 1; i < values.length; i++) {
      d += ' H' + xAt(i) + ' V' + yAt(values[i]);
    }
    return d;
  }

  var seriesStagger = 0.25;
  var dotStagger    = Math.min(0.25, 1.0 / n);
  var lastDelay     = (series.length - 1) * seriesStagger + (n - 1) * dotStagger;
  var readyDelay    = (lastDelay + 0.8 + 0.1) * 1000;

  /* BUILD */
  series.forEach(function(s, si) {
    var sg = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    sg.setAttribute('class', 'sg');
    sg.setAttribute('id', 'sg' + si);

    /* hit path — painted first so it sits under the visible line */
    var hitPath = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    hitPath.setAttribute('class', 'series-hit');
    hitPath.setAttribute('d', jumpPath(s.values));
    sg.appendChild(hitPath);

    /* visible line */
    var path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    path.setAttribute('class', 'series-path line-' + s.cls);
    path.setAttribute('d', jumpPath(s.values));
    path.setAttribute('fill', 'none');
    path.setAttribute('stroke-width', '2.5');
    path.setAttribute('stroke-linejoin', 'round');
    path.style.animationDelay = (si * seriesStagger) + 's';
    sg.appendChild(path);

    /* dots */
    s.values.forEach(function(v, i) {
      var dg = document.createElementNS('http://www.w3.org/2000/svg', 'g');
      dg.setAttribute('class', 'dot-g');
      dg.style.animationDelay = (si * seriesStagger + i * dotStagger) + 's';

      var dot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      dot.setAttribute('cx', xAt(i)); dot.setAttribute('cy', yAt(v)); dot.setAttribute('r', '5');
      dot.setAttribute('class', 'dot-circle series-' + s.cls);

      var ring = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      ring.setAttribute('cx', xAt(i)); ring.setAttribute('cy', yAt(v)); ring.setAttribute('r', '5');
      ring.setAttribute('fill', 'none');
      ring.setAttribute('class', 'line-' + s.cls);
      ring.setAttribute('stroke-width', '2');

      dg.appendChild(dot);
      dg.appendChild(ring);
      sg.appendChild(dg);
    });

    dataLayerEl.appendChild(sg);

    /* §3 A1 — per-element animationend wires .visible; no both fill-mode needed */
    path.style.animation = 'lineFadeIn 0.8s ease-out ' + (si * seriesStagger).toFixed(2) + 's';
    path.addEventListener('animationend', function() {
      path.style.animation = 'none';
      path.classList.add('visible');
    }, { once: true });

    Array.prototype.forEach.call(sg.querySelectorAll('.dot-g'), function(dg, di) {
      var delay = (si * seriesStagger + di * dotStagger).toFixed(2);
      dg.style.animation = 'lineFadeIn 0.8s ease-out ' + delay + 's';
      dg.addEventListener('animationend', function() {
        dg.style.animation = 'none';
        dg.classList.add('visible');
      }, { once: true });
    });
  });

  /* §3/§4 — gate hover on .ready after last animation completes */
  setTimeout(function() {
    dataLayerEl.classList.add('ready');
  }, readyDelay);

  /* TOOLTIP */
  var tip    = document.getElementById('tip');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  function showTip(cx, cy, valTxt, lblTxt) {
    tipVal.textContent = valTxt;
    tipLbl.textContent = lblTxt;
    var pad = 20, bh = 38, rx = 9, tw = 8, tail = 10;
    var hw  = Math.max(tipVal.getBBox().width, tipLbl.getBBox().width) / 2 + pad / 2;
    var tx  = Math.max(hw + 8, Math.min(cx, plotR - hw - 8));
    var above = (cy - tail - bh - 4) >= plotT;
    var bT, bB;
    if (above) { bB = cy - tail; bT = bB - bh; }
    else        { bT = cy + tail; bB = bT + bh; }

    tipBg.setAttribute('x', tx - hw); tipBg.setAttribute('y', bT);
    tipBg.setAttribute('width', hw * 2); tipBg.setAttribute('height', bh);

    if (above) {
      tipBdr.setAttribute('d',
        'M'+(tx+tw)+','+bB+' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+
        ' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+' L'+(tx-tw)+','+bB);
      tipTip.setAttribute('d', 'M'+(tx-tw)+','+bB+' L'+tx+','+(cy-2)+' L'+(tx+tw)+','+bB);
    } else {
      tipBdr.setAttribute('d',
        'M'+(tx-tw)+','+bT+' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+
        ' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+' L'+(tx+tw)+','+bT);
      tipTip.setAttribute('d', 'M'+(tx+tw)+','+bT+' L'+tx+','+(cy+2)+' L'+(tx-tw)+','+bT);
    }

    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', bT + bh * 0.32);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', bT + bh * 0.72);
    tip.style.opacity = '1';
  }

  function hideTip() {
    tip.style.opacity = '';
  }

  /* HOVER — sg-level; hit path captures every segment */
  function svgMouseX(e) {
    var pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
  }

  function nearestIdx(mx) {
    return Math.max(0, Math.min(n - 1, Math.round((mx - plotL) / step)));
  }

  var sgEls = Array.prototype.slice.call(dataLayerEl.querySelectorAll('.sg'));

  sgEls.forEach(function(sgEl, si) {
    var s = series[si];
    function onMove(e) {
      if (!dataLayerEl.classList.contains('ready')) return;
      sgEls.forEach(function(el) { el.classList.remove('hovered'); });
      Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.dot-g'), function(el) { el.classList.remove('hovered'); });
      dataLayerEl.classList.add('hovering');
      sgEl.classList.add('hovered');
      var idx   = nearestIdx(svgMouseX(e));
      var dotGs = sgEl.querySelectorAll('.dot-g');
      if (dotGs[idx]) dotGs[idx].classList.add('hovered');
      showTip(xAt(idx), yAt(s.values[idx]), s.values[idx].toFixed(2) + '%', s.name + ' \u00b7 ' + quarters[idx]);
    }
    sgEl.addEventListener('mouseenter', onMove);
    sgEl.addEventListener('mousemove',  onMove);
  });

  dataLayerEl.addEventListener('mouseleave', function() {
    sgEls.forEach(function(el) { el.classList.remove('hovered'); });
    Array.prototype.forEach.call(dataLayerEl.querySelectorAll('.dot-g'), function(el) { el.classList.remove('hovered'); });
    dataLayerEl.classList.remove('hovering');
    hideTip();
  });

  /* PRINT TOGGLE */

  /* DARK MODE */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
